<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  ledger</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> asset</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> transfer</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
